import 'dart:convert';
import 'dart:io';
import 'package:shelf/shelf.dart';
import 'package:shelf/shelf_io.dart' as shelf_io;

import 'package:option_2_static_shelf/cloudevents.dart';
import 'package:option_2_static_shelf/handlers.dart' as handlers;
import 'package:option_2_static_shelf/src/generated/storage_object_data.dart';

void main(List<String> args) async {
  // Read port parameters from environment (standard GCP Cloud Run contract)
  final portStr = Platform.environment['PORT'] ?? '8080';
  final port = int.tryParse(portStr) ?? 8080;

  // Build high-performance Shelf pipeline
  final pipeline = const Pipeline()
      .addMiddleware(_gcpStructuredLoggingMiddleware)
      .addMiddleware(_forbiddenAssetMiddleware)
      .addHandler(_router);

  final server = await shelf_io.serve(pipeline, InternetAddress.anyIPv4, port);
  print('Listening on port :${server.port} (Static Micro-Engine server)');
}

/// Dynamic routing resolver using lightning-fast static pointer indices.
Future<Response> _router(Request request) async {
  // Standard liveness probe for Cloud Run service agents
  if (request.url.path == 'healthz' || request.url.path == '') {
    return Response.ok('Healthy');
  }

  // Retrieve routing metadata
  final eventType = request.headers['ce-type'] ?? '';
  final path = request.url.path;

  // Route matches path and structural trigger signatures
  if (path == 'events/uploads' &&
      eventType == 'google.cloud.storage.object.v1.finalized') {
    try {
      // 1. Single-pass unpack bytes straight into target structure
      final event = await CloudEvent.parse<StorageObjectData>(
        request,
        (bytes) => StorageObjectData.fromBuffer(bytes),
      );

      // 2. Safely call developer typed callback handler
      handlers.onStorageUpload(event);

      return Response.ok('Processed');
    } catch (e, stack) {
      stderr.writeln('Internal processing failure: $e\n$stack');
      return Response.internalServerError(body: 'Internal failure');
    }
  }

  return Response.notFound(
      'Unsupported event type: $eventType on route / $path');
}

/// Standard middleware blocking scanning bots on standard routes
const _forbiddenAssets = {'robots.txt', 'favicon.ico'};
Handler _forbiddenAssetMiddleware(Handler innerHandler) => (Request request) {
      if (_forbiddenAssets.contains(request.url.path)) {
        return Response.notFound('Forbidden asset.');
      }
      return innerHandler(request);
    };

/// 🌟 GCP structured logging middleware.
/// Automatically outputs JSON format logs into stdout/stderr for Google Cloud Logging,
/// providing advanced trace mapping and correlation with zero CPU reflection steps.
Middleware _gcpStructuredLoggingMiddleware = (Handler innerHandler) {
  return (Request request) async {
    final response = await innerHandler(request);

    // Read Cloud Trace Context headers sent by Cloud Run frontend routing agent
    final traceHeader = request.headers['x-cloud-trace-context'] ?? '';
    final traceParts = traceHeader.split('/');
    final traceId = traceParts.first;

    // Output clean JSON format mapped naturally in GCP Logging
    final logMessage = {
      'severity': response.statusCode >= 500 ? 'ERROR' : 'INFO',
      'message':
          '${request.method} ${request.url.path} -> HTTP ${response.statusCode}',
      'httpRequest': {
        'requestMethod': request.method,
        'requestUrl': request.requestedUri.toString(),
        'status': response.statusCode,
        'userAgent': request.headers['user-agent'] ?? '',
      },
      if (traceId.isNotEmpty) 'logging.googleapis.com/trace': traceId,
    };

    print(jsonEncode(logMessage));
    return response;
  };
};
